// src/pages/CartPage/index.jsx

import React from 'react';
import { useSelector } from 'react-redux';
import CartItem from '../../components/CartItem'; // Будет создан ниже
import OrderForm from '../../components/OrderForm'; // Будет создан ниже
import s from './CartPage.module.css';

const CartPage = () => {
  const cartItems = useSelector(state => state.cart.items);

  // Расчет итоговой суммы
  const totalAmount = cartItems.reduce((acc, item) => {
    // Используем цену, сохраненную в cartSlice (которая уже со скидкой, если была)
    return acc + item.price * item.count; 
  }, 0);

  // Форматируем сумму до двух знаков после запятой
  const formattedTotal = totalAmount.toFixed(2);

  if (cartItems.length === 0) {
    return (
      <div className={s.emptyContainer}>
        <h1>Ваша корзина пуста</h1>
        <p>Начните покупки с просмотра нашего каталога!</p>
        {/* TODO: Добавить кнопку "В каталог" с Link */}
      </div>
    );
  }

  return (
    <div className={s.container}>
      <h1>Корзина</h1>
      <div className={s.content}>

        {/* 1. Список товаров в корзине */}
        <div className={s.itemsList}>
          {cartItems.map(item => (
            <CartItem 
              key={item.id} 
              item={item} 
            />
          ))}
        </div>

        {/* 2. Область оформления заказа */}
        <div className={s.orderSummary}>
          <h2>Детали заказа</h2>
          <div className={s.total}>
            <span>Итого:</span>
            <span className={s.totalPrice}>{formattedTotal} $</span>
          </div>

          <OrderForm total={formattedTotal} /> {/* Подключаем форму */}
        </div>

      </div>
    </div>
  );
};

export default CartPage;
